SELECT t.topic_id AS topicId, t.topic_name AS topicName, t.academic_year AS academicYear, t.max_students AS maxStudents, t.current_count AS currentCount, t.status, t.description, t.campus_id AS campusId, t.campus_name AS campusName, t.create_time AS createTime, t.update_time AS updateTime FROM project_topic t WHERE t.is_deleted = 0
AND t.campus_id = #{campusId}
AND t.campus_name LIKE CONCAT('%', #{campusName}, '%')
AND t.academic_year = #{academicYear}
AND t.status = #{status}
AND t.topic_name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY t.topic_id DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM project_topic t
WHERE t.is_deleted = 0

    AND t.campus_id = #{campusId}


    AND t.campus_name LIKE CONCAT('%', #{campusName}, '%')


    AND t.academic_year = #{academicYear}


    AND t.status = #{status}


    AND t.topic_name LIKE CONCAT('%', #{keyword}, '%')

SELECT t.topic_id AS topicId, t.topic_name AS topicName, t.academic_year AS academicYear, t.max_students AS maxStudents, t.current_count AS currentCount, t.status, t.description, t.campus_id AS campusId, t.campus_name AS campusName, t.create_time AS createTime, t.update_time AS updateTime FROM project_topic t WHERE t.is_deleted = 0
AND t.campus_id = #{campusId}
AND t.campus_name LIKE CONCAT('%', #{campusName}, '%')
AND t.academic_year = #{academicYear}
AND t.status = #{status}
AND t.topic_name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY t.topic_id DESC

SELECT t.topic_id AS topicId, t.topic_name AS topicName, t.description, t.teacher_id AS teacherId, tea.real_name AS teacherName, tea.teacher_no AS teacherNo, t.max_students AS maxStudents, t.current_count AS currentCount, t.status, t.academic_year AS academicYear, t.create_time AS createTime FROM project_topic t LEFT JOIN sys_user tea ON t.teacher_id = tea.user_id AND tea.is_deleted = 0 WHERE t.is_deleted = 0 AND t.status = 'OPEN'
AND t.campus_id = #{campusId}
AND t.campus_name = #{campusName}
AND t.teacher_id = #{teacherId}
AND t.academic_year LIKE CONCAT(#{academicYear}, '%')
ORDER BY t.create_time DESC
